-- Split into smaller files to keep D1 migration statements manageable.

UPDATE core_vocabulary SET word = 'know', meaning_zh = '知道；认识；了解', definition_en = 'to have information, understanding, or familiarity with someone or something', primary_part_of_speech = 'verb', phonetic_us = '/noʊ/', phonetic_uk = '/nəʊ/', updated_at = CURRENT_TIMESTAMP WHERE id = 'know';
UPDATE vocabulary_pronunciations SET phonetic = CASE accent WHEN 'us' THEN '/noʊ/' WHEN 'uk' THEN '/nəʊ/' ELSE phonetic END, phonetic_source = 'manual-curation', updated_at = CURRENT_TIMESTAMP WHERE vocabulary_id = 'know' AND accent IN ('us', 'uk');

